  ('disabled-10ced7e2-moex-00220', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於人民不服行政處分之救濟，下列敘述何者正確？', '["不服國家通訊傳播委員會之行政處分，應先向行政院提起訴願後，始可 提起行政訴訟", "不服公平交易委員會之行政處分，應先向行政院提起訴願後，始可提起 行政訴訟", "公立學校職員不服學校對其所為之曠職登記，得提起行政訴訟", "不服交通監理機關之交通裁罰處分，應先向其上級機關提起訴願後，始 可提起行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00221', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '衛生福利部依食品安全衛生管理法第22條第1項第10款規定「原料之容 器或外包裝，應以中文及通用符號，明顯標示下列事項：十、其他經中央 主管機關公告之事項」公告相關事項。業者甲認為該公告事項太過浮濫， 已造成營業損失。甲如何救濟？', '["該公告為對人之一般處分，甲得提起訴願請求撤銷之", "該公告為法規命令，現行行政訴訟制度並無法規審查程序", "甲得提起一般給付之訴，請求主管機關廢止該公告", "甲得類推都市計畫審查程序，以公告機關為被告，向管轄之高等行政法 院提起訴訟，請求宣告該公告無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00222', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '下列何者非屬行政處分程序瑕疵之補正？', '["低收入戶未經申請的延長生活補貼，事後補提申請", "於訴願終結前，建管機關對駁回申請處分補記理由", "應該以證書方式作成而未給予證書，事後補發證書", "多階段行政處分，應參與之其他機關已於事後參與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00223', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於國家賠償之敘述，下列何者錯誤？', '["法官因執行職務侵害人民自由或權利，就其參與審判或追訴案件犯職務 上之罪，經判決有罪確定者，有國家賠償法規定之適用", "檢察官因執行職務侵害人民自由或權利，就其參與審判或追訴案件犯職 務上之罪，經判決有罪確定者，有國家賠償法規定之適用", "警察機關以契約委託民間拖吊業者執行拖吊違規車輛，造成受拖吊車主 之損害，該車主可向執行之警察機關主張國家賠償", "甲為私法人之民間基金會，其雖受乙行政機關委託執行公權力，但因甲 為私法人，故人民不得對其主張國家賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00224', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於徵收補償之憲法內涵，依照司法院解釋，下列敘述何者正確？', '["徵收處分作成後，如未於法定期限內發給補償，該處分失效", "補償與損失必須一致，故應採完全補償原則", "基於財產權之價值保障，補償方式限以金錢為之", "補償之對象，限於土地所有權人，不及於該土地之其他財產權人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00225', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-111-b96fcbef', 'sub-disabled-10ced7e2-04', NULL, 'essay', '22 歲之甲將其 A電腦借給16 歲之乙。其後乙將該電腦出賣、讓與及交付
給 21 歲之丙。事後證實丙知悉乙並非該電腦之所有人，試問：甲、乙與
乙、丙之間所為各該法律行為之效力如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "5f8f278b7bb2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "301", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00226', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-111-b96fcbef', 'sub-disabled-10ced7e2-04', NULL, 'essay', '30 歲之甲委任並授與 17歲之乙處理其 A商號事務之代理權，乙於受委任
契約之期間，依代理人之身分以甲之名義以新臺幣 20 萬元之價金向丙購
買 B 貨物，事後發現甲與乙間的有償委任契約因乙之法定代理人拒絕承
認而無效，試問：甲、丙間法律行為效力如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "5f8f278b7bb2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "301", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00227', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-111-b96fcbef', 'sub-disabled-10ced7e2-04', NULL, 'essay', '甲所任職的公司因疫情影響，大舉裁員，甲也在即將被裁員之列。甲為此
對老闆乙心生怨恨、萌生殺意。甲明知乙每日進公司前，秘書丙都會事先
泡好乙愛喝的咖啡，放在乙的辦公室桌上，以便乙一進辦公室即可飲用。
某日早晨，甲利用丙泡完咖啡放在乙桌上之後，悄悄潛入乙的辦公室，在
乙的咖啡裡摻入足以致命的劇毒。不料甲在摻完劇毒、攪拌咖啡時，丙便
進入辦公室，詢問甲在老闆辦公室裡做什麼。甲一時心急，深怕事跡敗露、
難逃法網，遂答以我剛剛看到你泡的咖啡裡有雜物，幫你倒掉，免得老闆
發現生氣。語畢，甲隨即將咖啡倒入乙辦公室內的流理台內，以清水沖走。
丙儘管感到莫名其妙，還是立刻幫乙重泡一杯咖啡，乙也剛好就進入辦公
室辦公，飲用重新泡好的咖啡，且對上開事發經過則是毫無所悉。請詳述
甲是否須為其行為負擔刑責？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "5f8f278b7bb2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "301", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00228', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-111-b96fcbef', 'sub-disabled-10ced7e2-04', NULL, 'essay', '甲為實行電信詐騙，在菲律賓花費新臺幣（下同）20 萬元購買電信設備，
且以 5萬元購買被害人個資名單，遂開始打電話回臺灣，向被害人冒稱自
己為檢察官行騙。甲於騙得200萬元後，遂將前開電信設備與個資名單銷
毀，攜帶鉅款返國。甲返國後，遭菲律賓警方通報我國警方偵辦，警方並
扣得甲所攜帶之現金 150 萬元，其餘款項經甲供稱皆已花用一空。試問：
甲之詐騙行為是否有我國刑法之適用？（5分）
甲如經法院判決有罪，法院得宣告沒收之範圍與數額為何？（20 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "5f8f278b7bb2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "301", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
